const body = $input.first().json.body || $input.first().json;
const tenantId = body.tenantId;
const automationId = body.automationId;
const config = body.config || {};

if (!tenantId || !automationId) {
  return [{ json: { success: false, error: 'tenantId et automationId requis' } }];
}

return [{ json: { tenantId, automationId, config, valid: true } }];

const info = $input.first().json;
const data = $('02. Valider').first().json;

if (!info || !info.code) {
  return [{ json: { success: false, error: 'Automatisation ou tenant introuvable' } }];
}

return [{ json: {
  tenantId: data.tenantId,
  automationId: data.automationId,
  code: info.code,
  nom: info.nom,
  tenantName: info.tenant_name,
  setupPrice: Number(info.setup_price) || 0,
  monthlyPrice: Number(info.monthly_price) || 0,
  config: data.config
} }];

const purchase = $input.first().json;
const data = $('04. Preparer').first().json;

return [{ json: {
  success: true,
  workflowId: null,
  workflowName: data.nom,
  workflowIds: [],
  folderId: null,
  folderName: 'client:' + data.tenantName,
  purchaseId: purchase.id,
  purchaseStatus: purchase.status,
  message: 'Automatisation ' + data.nom + ' activee pour ' + data.tenantName
} }];
